function findSuperstarDishes(a, n) {
    let el1 = -Infinity, el2 = -Infinity;
    let cnt1 = 0, cnt2 = 0;

    // Phase 1: Voting
    for (let i = 0; i < n; i++) {
        if (a[i] === el1) cnt1++;
        else if (a[i] === el2) cnt2++;
        else if (cnt1 === 0) {
            el1 = a[i];
            cnt1 = 1;
        }
        else if (cnt2 === 0) {
            el2 = a[i];
            cnt2 = 1;
        }
        else {
            cnt1--;
            cnt2--;
        }
    }

    // Phase 2: Validation
    cnt1 = 0;
    cnt2 = 0;

    for (let i = 0; i < n; i++) {
        if (a[i] === el1) cnt1++;
        else if (a[i] === el2) cnt2++;
    }

    const ans = [];
    if (cnt1 > Math.floor(n / 3)) ans.push(el1);
    if (cnt2 > Math.floor(n / 3)) ans.push(el2);

    ans.sort((a, b) => a - b);
    return ans;
}
